    "sessionSummary": [
      "Polynomials are expressions with non-negative integer powers. We classify them by degree (linear/quadratic/cubic) and terms (mono/bi/tri)."
    ],
    "endOfClassRecap": [
      {
        "prompt": "A polynomial cannot have variables in the ________ or under a ________ sign.",
        "expectedAnswer": "denominator, root"
      }
    ],
    "nextSessionBridge": [
      "Today we learned what polynomials are. Next time, we will learn how to find their 'zeroes' (roots)."
    ]
  },
